1	/**
2	 * Vault Overview Page Content
3	 *
4	 * Main dashboard for Vault Managers. Displays vault status, metrics,
5	 * cashier shift requests, and quick actions for cash movements.
6	 *
7	 * @module components/VAULT/overview/VaultOverviewPageContent
8	 */
9	
10	'use client';
11	
12	import VaultManagerHeader from '@/components/VAULT/layout/VaultManagerHeader';
13	import {
14	  DEFAULT_VAULT_BALANCE,
15	  DEFAULT_VAULT_METRICS,
16	} from '@/components/VAULT/overview/data/defaults';
17	import StaleShiftDetectedBlock from '@/components/VAULT/shared/StaleShiftDetectedBlock';
18	import PageLayout from '@/components/shared/layout/PageLayout';
19	import { Button } from '@/components/shared/ui/button';
20	import { DEFAULT_POLL_INTERVAL } from '@/lib/constants';
21	import { fetchCabinetsForLocation } from '@/lib/helpers/cabinets/helpers';
22	import {
23	  fetchGlobalVaultOverviewData,
24	  fetchVaultOverviewData,
25	} from '@/lib/helpers/vaultHelpers';
26	import { useUserStore } from '@/lib/store/userStore';
27	import { isShiftStale } from '@/lib/utils/vault/shift';
28	import type { GamingMachine } from '@/shared/types/entities';
29	import {
30	  type CashDesk,
31	  type Denomination,
32	  type FloatRequest,
33	  type UnbalancedShiftInfo,
34	  type VaultBalance,
35	  type VaultMetrics,
36	  type VaultTransaction,
37	} from '@/shared/types/vault';
38	import { FileText, RefreshCw } from 'lucide-react';
39	import Link from 'next/link';
40	import { useCallback, useEffect, useMemo, useState } from 'react';
41	import { toast } from 'sonner';
42	
43	// Type for data passed to handleModalConfirm
44	type ModalFormData = {
45	  // Expense fields
46	  category?: string;
47	  amount?: number;
48	  description?: string;
49	  date?: Date | string;
50	  denominations?: Denomination[];
51	  bankDetails?: Record<string, string>;
52	  expenseDetails?: Record<string, unknown>;
53	  file?: File;
54	  // Add Cash / Remove Cash fields
55	  totalAmount?: number;
56	  source?: string;
57	  notes?: string;
58	  // Initialise / reconcile / close
59	  openingBalance?: number;
60	  vaultShiftId?: string;
61	  reason?: string;
62	  comment?: string;
63	  newBalance?: number;
64	  [key: string]: unknown;
65	};
66	
67	// Sections
68	import VaultOverviewAdvancedDashboard from './sections/VaultOverviewAdvancedDashboard';
69	import VaultOverviewFloatRequestsPanel from './sections/VaultOverviewFloatRequestsPanel';
70	import VaultOverviewShiftReviewPanel from './sections/VaultOverviewShiftReviewPanel';
71	
72	// Skeleton & Base UI
73	import VaultOverviewSkeleton from '@/components/ui/skeletons/VaultOverviewSkeleton';
74	
75	// Panel Components
76	import VaultOverviewBalanceCard from '@/components/VAULT/overview/cards/VaultOverviewBalanceCard';
77	import VaultOverviewInventoryCard from '@/components/VAULT/overview/cards/VaultOverviewInventoryCard';
78	import VaultOverviewQuickActionsSection from '@/components/VAULT/overview/sections/VaultOverviewQuickActionsSection';
79	import VaultOverviewRecentActivitySection from '@/components/VAULT/overview/sections/VaultOverviewRecentActivitySection';
80	
81	// Extracted Sections
82	import VaultOverviewCashDesksSection from './sections/VaultOverviewCashDesksSection';
83	import VaultOverviewHealthGrid from './sections/VaultOverviewHealthGrid';
84	import VaultOverviewModals from './sections/VaultOverviewModals';
85	import VaultOverviewShiftPromotion from './sections/VaultOverviewShiftPromotion';
86	
87	// Hooks
88	import { useVaultLicencee } from '@/lib/hooks/vault/useVaultLicencee';
89	
90	/**
91	 * Vault Overview Component
92	 */
93	export default function VaultOverviewPageContent() {
94	  const {
95	    user,
96	    setHasActiveVaultShift,
97	    setIsVaultReconciled,
98	    setIsStaleShift,
99	  } = useUserStore();
100	
101	  // Role Detection
102	  const isAdminOrDev = user?.roles?.some(r =>
103	    ['admin', 'developer'].includes(r.toLowerCase())
104	  );
105	
106	  // ============================================================================
107	  // State & Hooks
108	  // ============================================================================
109	
110	  // Data State
111	  const [vaultBalance, setVaultBalance] = useState<VaultBalance>(
112	    DEFAULT_VAULT_BALANCE
113	  );
114	  const [metrics, setMetrics] = useState<VaultMetrics>(DEFAULT_VAULT_METRICS);
115	  const [transactions, setTransactions] = useState<VaultTransaction[]>([]);
116	  const [pendingShifts, setPendingShifts] = useState<UnbalancedShiftInfo[]>([]);
117	  const [floatRequests, setFloatRequests] = useState<FloatRequest[]>([]);
118	  const [cashDesks, setCashDesks] = useState<CashDesk[]>([]);
119	  const [machines, setMachines] = useState<GamingMachine[]>([]);
120	
121	  // Loading States
122	  const { licenceeId: selectedLicencee, setLicenceeId: setSelectedLicencee } =
123	    useVaultLicencee();
124	  const [loading, setLoading] = useState(true);
125	  const [refreshing, setRefreshing] = useState(false);
126	  const [shiftReviewLoading, setShiftReviewLoading] = useState(false);
127	
128	  // Modal Visibility State
129	  const [modals, setModals] = useState({
130	    addCash: false,
131	    removeCash: false,
132	    recordExpense: false,
133	    reconcile: false,
134	    initialize: false,
135	    softCount: false,
136	    viewDenominations: false,
137	    closeShift: false,
138	  });
139	
140	  const [viewDenomsData, setViewDenomsData] = useState<{
141	    title: string;
142	    denominations: Denomination[];
143	    total: number;
144	  } | null>(null);
145	
146	  // Derived shift state — needed by effects below
147	  const isShiftActive = !!vaultBalance.activeShiftId;
148	  const isReconciled = !!vaultBalance.isReconciled;
149	
150	  // ============================================================================
151	  // Effects
152	  // ============================================================================
153	
154	  /**
155	   * Fetch all vault data for the current location
156	   */
157	  const fetchData = useCallback(
158	    async (isSilent = false) => {
159	      // If Admin/Dev, allow global fetch even without assigned location
160	      if (!isAdminOrDev && !user?.assignedLocations?.[0]) {
161	        setLoading(false);
162	        return;
163	      }
164	
165	      // For normal users, require location
166	      const locationId = user?.assignedLocations?.[0];
167	
168	      if (!isSilent) setLoading(true);
169	      else setRefreshing(true);
170	
171	      try {
172	        let data;
173	        if (isAdminOrDev) {
174	          // fetch global data with licencee filter
175	          data = await fetchGlobalVaultOverviewData(selectedLicencee);
176	        } else if (locationId) {
177	          data = await fetchVaultOverviewData(locationId, user?.username || '');
178	        } else {
179	          throw new Error('No location assigned');
180	        }
181	
182	        setVaultBalance(data.vaultBalance);
183	        setMetrics(data.metrics);
184	        setTransactions(data.transactions);
185	        setPendingShifts(data.pendingShifts);
186	        setFloatRequests(data.floatRequests);
187	        setCashDesks(data.cashDesks);
188	
189	        // Sync with global store
190	        setIsStaleShift(isShiftStale(data.vaultBalance.openedAt));
191	
192	        // Fetch machines for selection (Only for non-admin/dev users with a valid location)
193	        // Admins/devs are in read-only mode and don't need machine selection for vault modals
194	        if (!isAdminOrDev && locationId) {
195	          try {
196	            const machinesData = await fetchCabinetsForLocation(
197	              locationId,
198	              undefined,
199	              'Today'
200	            );
201	            if (machinesData && machinesData.data) {
202	              setMachines(machinesData.data);
203	            }
204	          } catch (err) {
205	            console.error('Failed to fetch machines for vault', err);
206	          }
207	        }
208	      } catch (error) {
209	        console.error('Failed to fetch vault data', error);
210	        toast.error('Failed to load vault data');
211	      } finally {
212	        setLoading(false);
213	        setRefreshing(false);
214	      }
215	    },
216	    [user?.assignedLocations, user?.username, selectedLicencee, isAdminOrDev]
217	  );
218	
219	  /**
220	   * Refetch data when location or licencee changes
221	   */
222	  useEffect(() => {
223	    fetchData();
224	  }, [user?.assignedLocations, selectedLicencee, fetchData]);
225	
226	  useEffect(() => {
227	    // STEP: Periodic refresh for float requests and notifications
228	    const interval = setInterval(() => {
229	      fetchData(true); // Silent refresh
230	    }, DEFAULT_POLL_INTERVAL); // 5 seconds
231	
232	    return () => clearInterval(interval);
233	  }, [fetchData]);
234	
235	  useEffect(() => {
236	    setHasActiveVaultShift(isShiftActive);
237	    setIsVaultReconciled(isReconciled);
238	  }, [
239	    isShiftActive,
240	    isReconciled,
241	    setHasActiveVaultShift,
242	    setIsVaultReconciled,
243	  ]);
244	
245	  // ============================================================================
246	  // Handlers
247	  // ============================================================================
248	
249	  /**
250	   * Approve/Deny/Edit Float Requests
251	   */
252	  const handleFloatApprove = async (
253	    requestId: string,
254	    approvedAmount?: number,
255	    approvedDenominations?: Denomination[]
256	  ) => {
257	    try {
258	      const res = await fetch('/api/vault/float-request/approve', {
259	        method: 'POST',
260	        headers: { 'Content-Type': 'application/json' },
261	        body: JSON.stringify({
262	          requestId,
263	          status: 'approved',
264	          approvedAmount,
265	          approvedDenominations,
266	        }),
267	      });
268	      const data = await res.json();
269	      if (data.success) {
270	        toast.success('Float request approved');
271	        fetchData(true);
272	      } else {
273	        toast.error(data.error || 'Failed to approve request');
274	      }
275	    } catch {
276	      toast.error('Network error');
277	    }
278	  };
279	
280	  const handleFloatDeny = async (requestId: string, reason?: string) => {
281	    try {
282	      const res = await fetch('/api/vault/float-request/approve', {
283	        method: 'POST',
284	        headers: { 'Content-Type': 'application/json' },
285	        body: JSON.stringify({ requestId, status: 'denied', vmNotes: reason }),
286	      });
287	      const data = await res.json();
288	      if (data.success) {
289	        toast.success('Float request denied');
290	        fetchData(true);
291	      } else {
292	        toast.error(data.error || 'Failed to deny request');
293	      }
294	    } catch {
295	      toast.error('Network error');
296	    }
297	  };
298	
299	  const handleFloatEdit = async (
300	    requestId: string,
301	    amount: number,
302	    denominations: Denomination[],
303	    notes?: string
304	  ) => {
305	    try {
306	      const res = await fetch('/api/vault/float-request/approve', {
307	        method: 'POST',
308	        headers: { 'Content-Type': 'application/json' },
309	        body: JSON.stringify({
310	          requestId,
311	          status: 'edited',
312	          approvedAmount: amount,
313	          approvedDenominations: denominations,
314	          vmNotes: notes,
315	        }),
316	      });
317	      const data = await res.json();
318	      if (data.success) {
319	        toast.success('Float request updated');
320	        fetchData(true);
321	      } else {
322	        toast.error(data.error || 'Failed to update request');
323	      }
324	    } catch {
325	      toast.error('Network error');
326	    }
327	  };
328	
329	  const handleFloatConfirm = async (requestId: string) => {
330	    try {
331	      const res = await fetch('/api/vault/float-request/confirm', {
332	        method: 'POST',
333	        headers: { 'Content-Type': 'application/json' },
334	        body: JSON.stringify({ requestId }),
335	      });
336	      const data = await res.json();
337	      if (data.success) {
338	        toast.success('Float return confirmed and vault updated');
339	        fetchData(true);
340	      } else {
341	        toast.error(data.error || 'Failed to confirm receipt');
342	      }
343	    } catch {
344	      toast.error('Network error');
345	    }
346	  };
347	
348	  /**
349	   * Resolve Shift Discrepancies
350	   */
351	  const handleShiftResolveConfirm = async (
352	    shiftId: string,
353	    finalBalance: number,
354	    auditComment: string,
355	    denominations?: Denomination[]
356	  ) => {
357	    setShiftReviewLoading(true);
358	    try {
359	      const res = await fetch('/api/cashier/shift/resolve', {
360	        method: 'POST',
361	        headers: { 'Content-Type': 'application/json' },
362	        body: JSON.stringify({
363	          shiftId,
364	          finalBalance,
365	          auditComment,
366	          denominations,
367	        }),
368	      });
369	      const data = await res.json();
370	      if (data.success) {
371	        toast.success('Shift discrepancy resolved');
372	        fetchData(true);
373	      } else {
374	        toast.error(data.error || 'Failed to resolve shift');
375	      }
376	    } catch {
377	      toast.error('Network error');
378	    } finally {
379	      setShiftReviewLoading(false);
380	    }
381	  };
382	
383	  const handleShiftReject = async (shiftId: string, reason: string) => {
384	    setShiftReviewLoading(true);
385	    try {
386	      const res = await fetch('/api/cashier/shift/reject', {
387	        method: 'POST',
388	        headers: { 'Content-Type': 'application/json' },
389	        body: JSON.stringify({ shiftId, reason }),
390	      });
391	      const data = await res.json();
392	      if (data.success) {
393	        toast.success('Shift closure rejected and returned to cashier');
394	        fetchData(true);
395	      } else {
396	        toast.error(data.error || 'Failed to reject shift');
397	      }
398	    } catch {
399	      toast.error('Network error');
400	    } finally {
401	      setShiftReviewLoading(false);
402	    }
403	  };
404	
405	  /**
406	   * Generic Modal Confirm Handlers
407	   */
408	  const handleResolveShift = handleShiftResolveConfirm;
409	  const handleModalConfirm = async (type: string, data?: ModalFormData) => {
410	    let endpoint = '';
411	    const method = 'POST';
412	
413	    // Base request body
414	    const requestPayload: Record<string, unknown> = {
415	      ...(data || {}),
416	      locationId: user?.assignedLocations?.[0],
417	    };
418	
419	    switch (type) {
420	      case 'addCash':
421	        endpoint = '/api/vault/add-cash';
422	        break;
423	      case 'removeCash':
424	        endpoint = '/api/vault/remove-cash';
425	        break;
426	      case 'recordExpense':
427	        endpoint = '/api/vault/expense';
428	        break;
429	      case 'reconcile':
430	        endpoint = '/api/vault/reconcile';
431	        requestPayload.vaultShiftId = vaultBalance.activeShiftId || null;
432	        break;
433	      case 'initialize':
434	        endpoint = '/api/vault/initialize';
435	        break;
436	      case 'closeShift':
437	        endpoint = '/api/vault/shift/close';
438	        requestPayload.vaultShiftId = vaultBalance.activeShiftId || null;
439	        break;
440	    }
441	
442	    if (type === 'collection' || type === 'softCount') {
443	      setModals(prev => ({ ...prev, [type]: false }));
444	      fetchData(true);
445	      return;
446	    }
447	
448	    if (!endpoint) return;
449	
450	    try {
451	      if (type === 'initialize' && data?.totalAmount !== undefined) {
452	        requestPayload.openingBalance = data.totalAmount;
453	      }
454	
455	      const isExpense = type === 'recordExpense';
456	      const isCashMovement = type === 'addCash' || type === 'removeCash';
457	
458	      let requestBody: FormData | string;
459	      const headers: Record<string, string> = {};
460	
461	      if (isExpense) {
462	        const fd = new FormData();
463	        fd.append('category', String(data?.category || ''));
464	        fd.append('amount', String(data?.amount ?? ''));
465	        fd.append('description', String(data?.description || ''));
466	        const dateVal = data?.date;
467	        fd.append(
468	          'date',
469	          dateVal instanceof Date
470	            ? dateVal.toISOString()
471	            : String(dateVal || '')
472	        );
473	        fd.append('denominations', JSON.stringify(data?.denominations || []));
474	
475	        // New Expense Fields
476	        if (data?.bankDetails)
477	          fd.append('bankDetails', JSON.stringify(data.bankDetails));
478	        if (data?.expenseDetails)
479	          fd.append('expenseDetails', JSON.stringify(data.expenseDetails));
480	
481	        fd.append('locationId', user?.assignedLocations?.[0] || '');
482	        if (data?.file) fd.append('file', data.file);
483	        requestBody = fd;
484	        // browser sets content-type for FormData
485	      } else {
486	        headers['Content-Type'] = 'application/json';
487	
488	        if (isCashMovement) {
489	          const { denominations, totalAmount, ...rest } = data || {};
490	          requestBody = JSON.stringify({
491	            ...rest,
492	            amount: totalAmount,
493	            denominations: denominations,
494	            locationId: user?.assignedLocations?.[0],
495	          });
496	        } else {
497	          requestBody = JSON.stringify(requestPayload);
498	        }
499	      }
500	
501	      const res = await fetch(endpoint, {
502	        method,
503	        headers,
504	        body: requestBody,
505	      });
506	
507	      const result = await res.json();
508	      if (result.success) {
509	        toast.success(result.message || 'Action completed');
510	        setModals(prev => {
511	          const next = { ...prev, [type]: false };
512	          // If we just initialized a shift, automatically open the reconcile modal
513	          if (type === 'initialize') {
514	            next.reconcile = true;
515	          }
516	          return next;
517	        });
518	        fetchData(true);
519	      } else {
520	        toast.error(result.error || 'Action failed');
521	      }
522	    } catch (error) {
523	      console.error('Network error during modal confirmation:', error);
524	      toast.error('Network error - check your connection');
525	    }
526	  };
527	
528	  // ============================================================================
529	  // Computed
530	  // ============================================================================
531	
532	  const isStaleShift = useMemo(() => {
533	    return isShiftStale(vaultBalance.openedAt);
534	  }, [vaultBalance.openedAt]);
535	
536	  const checkShiftStarted = useCallback(
537	    (actionKey?: string) => {
538	      if (!isShiftActive) {
539	        toast.error('Operation Blocked', {
540	          description:
541	            'You must start a vault shift before performing this operation.',
542	        });
543	        return false;
544	      }
545	
546	      if (
547	        isStaleShift &&
548	        actionKey !== 'closeShift' &&
549	        actionKey !== 'manageCashiers'
550	      ) {
551	        toast.error('Stale Shift Detected', {
552	          description:
553	            'This shift is from a previous gaming day. You must close this shift first.',
554	        });
555	        return false;
556	      }
557	
558	      // BR-X: Mandatory opening reconciliation
559	      if (
560	        !vaultBalance.isReconciled &&
561	        actionKey !== 'reconcile' &&
562	        actionKey !== 'closeShift' &&
563	        actionKey !== 'manageCashiers'
564	      ) {
565	        toast.error('Reconciliation Required', {
566	          description:
567	            'Please perform the mandatory opening reconciliation before continuing with other operations.',
568	        });
569	        return false;
570	      }
571	
572	      return true;
573	    },
574	    [isShiftActive, isStaleShift, vaultBalance.isReconciled]
575	  );
576	
577	  const handleAction = (actionKey: keyof typeof modals) => {
578	    if (!checkShiftStarted(actionKey)) return;
579	
580	    // STEP: Special handling for Close Day sequence (Handled by Header)
581	    if (actionKey === 'closeShift') {
582	      toast.info('Closing Day...', {
583	        description:
584	          'Please use the "Close Day" button in the header to start the end-of-day sequence.',
585	      });
586	      return;
587	    }
588	
589	    setModals(prev => ({ ...prev, [actionKey]: true }));
590	  };
591	
592	  // ============================================================================
593	  // Render
594	  // ============================================================================
595	
596	  // Guard: Check for critical missing user data (Skip check for Admin/Dev)
597	  if (!loading && !isAdminOrDev && !user?.assignedLocations?.[0]) {
598	    return (
599	      <PageLayout>
600	        <div className="flex h-64 items-center justify-center text-gray-500">
601	          No location assigned. Please contact your administrator.
602	        </div>
603	      </PageLayout>
604	    );
605	  }
606	
607	  if (loading) {
608	    return (
609	      <PageLayout>
610	        <VaultOverviewSkeleton />
611	      </PageLayout>
612	    );
613	  }
614	
615	  return (
616	    <PageLayout
617	      onRefresh={() => fetchData(false)}
618	      refreshing={refreshing}
619	      headerProps={
620	        isAdminOrDev
621	          ? {
622	              selectedLicencee,
623	              setSelectedLicencee,
624	              disabled: false,
625	            }
626	          : undefined
627	      }
628	    >
629	      <div className="space-y-6">
630	        {/* Header with Title & Notifications */}
631	        <VaultManagerHeader
632	          title={isAdminOrDev ? 'Global Vault Overview' : 'Vault Management'}
633	          showBack={false}
634	          onFloatActionComplete={() => fetchData(true)}
635	          vaultInventory={vaultBalance.denominations}
636	          description={
637	            <div className="flex items-center gap-2">
638	              <span>
639	                {new Date().toLocaleDateString('en-US', {
640	                  weekday: 'long',
641	                  year: 'numeric',
642	                  month: 'long',
643	                  day: 'numeric',
644	                })}
645	                {isAdminOrDev && (
646	                  <span className="ml-2 font-semibold text-orangeHighlight">
647	                    (Read Only Mode)
648	                  </span>
649	                )}
650	              </span>
651	              <Button
652	                variant="ghost"
653	                size="sm"
654	                onClick={() => fetchData(true)}
655	                disabled={refreshing}
656	                className="h-6 px-1.5 text-gray-400 hover:text-blue-600"
657	              >
658	                <RefreshCw
659	                  className={`h-3.5 w-3.5 ${refreshing ? 'animate-spin' : ''}`}
660	                />
661	              </Button>
662	            </div>
663	          }
664	        />
665	
666	        <StaleShiftDetectedBlock
667	          isStale={isStaleShift}
668	          openedAt={vaultBalance.openedAt}
669	          type="vault"
670	        >
671	          <div className="space-y-6">
672	            {!isAdminOrDev && (
673	              <VaultOverviewShiftPromotion
674	                activeShiftId={vaultBalance.activeShiftId}
675	                onStartShift={() =>
676	                  setModals(m => ({ ...m, initialize: true }))
677	                }
678	              />
679	            )}
680	
681	            <div className="flex justify-end">
682	              <Link href="/vault/management/reports/end-of-day">
683	                <Button
684	                  variant="outline"
685	                  className="gap-2 border-orangeHighlight text-orangeHighlight hover:bg-orangeHighlight/10"
686	                >
687	                  <FileText className="h-4 w-4" />
688	                  View End-of-Day Report
689	                </Button>
690	              </Link>
691	            </div>
692	
693	            {/* Balance Card Section */}
694	            <VaultOverviewBalanceCard
695	              balance={vaultBalance}
696	              isStaleShift={isStaleShift}
697	              onReconcile={
698	                isAdminOrDev ? undefined : () => handleAction('reconcile')
699	              }
700	              onViewDenominations={() => {
701	                const isShiftStarted = !!vaultBalance.activeShiftId;
