786	                isAdminOrDev
787	                  ? toast.info('Check only mode')
788	                  : handleAction('removeCash')
789	              }
790	              onRecordExpense={() =>
791	                isAdminOrDev
792	                  ? toast.info('Check only mode')
793	                  : handleAction('recordExpense')
794	              }
795	              onManageCashiers={() => {
796	                window.location.href = '/vault/management/cashiers';
797	              }}
798	              onSoftCount={
799	                isAdminOrDev ? undefined : () => handleAction('softCount')
800	              }
801	              onViewActivityLog={() => {
802	                window.location.href = '/vault/management/activity-log';
803	              }}
804	            />
805	
806	            <VaultOverviewRecentActivitySection transactions={transactions} />
807	
808	            {/* All Vault Modals */}
809	            <VaultOverviewModals
810	              modals={modals}
811	              vaultBalance={vaultBalance.balance}
