1	/**
2	 * Global Vault Overview API
3	 */
4	
5	import { GamingLocations } from '@/app/api/lib/models/gaminglocations';
6	import { Meters } from '@/app/api/lib/models/meters';
7	import { getGamingDayRangeForPeriod } from '@/lib/utils/gamingDayRange';
8	import { withApiAuth } from '@/app/api/lib/helpers/apiWrapper';
9	import {
10	  logRouteFetch,
11	  logRouteError,
12	  extractUserFromRequest,
13	} from '@/app/api/lib/utils/routeLogger';
14	import { NextRequest, NextResponse } from 'next/server';
15	import type { LocationDocument } from '@/lib/types/common';
16	import type {
17	  VaultShiftOverview,
18	  CashierShiftOverview,
19	  VaultTransactionOverview,
20	  EnrichedVaultTransactionOverview,
21	} from '@/shared/types/vault';
22	import type { UserOverview } from '@/shared/types/models';
23	import type {
24	  CashierShiftDocument,
25	  VaultShiftDocument,
26	  VaultTransactionDocument,
27	} from '@shared/types';
28	
29	/**
30	 * Main GET handler for global vault overview.
31	 *
32	 * STEP 1: Authorization and permission check.
33	 * STEP 2: Parse query parameters (licenceeId, timePeriod, date range).
34	 * STEP 3: Fetch locations and build location maps.
35	 * STEP 4: Import models and fetch active shifts, transactions, and float requests.
36	 * STEP 5: Aggregation and processing of balanced/transaction data.
37	 * STEP 6: Return formatted global overview data.
38	 *
39	 * @param {NextRequest} request - The incoming Next.js request.
40	 * @param {string} request.url - URL containing searchParams:
41	 *   - licenceeId: Filter by licencee (or 'all').
42	 *   - timePeriod: Gaming day preset ('Today', 'Yesterday', etc.).
43	 *   - startDate: Custom range start (ISO string).
44	 *   - endDate: Custom range end (ISO string).
45	 * @returns {Promise<NextResponse>} Structured global vault overview data.
46	 */
47	export async function GET(request: NextRequest) {
48	  const startTime = Date.now();
49	  const functionName = 'GET /api/vault/overview/global';
50	  const user = extractUserFromRequest(request);
51	
52	  return withApiAuth(request, async ({ isAdminOrDev }) => {
53	    // ============================================================================
54	    // STEP 1: Check permissions
55	    // ============================================================================
56	    if (!isAdminOrDev) {
57	      logRouteError(
58	        functionName,
59	        'GET',
60	        '/api/vault/overview/global',
61	        'Insufficient permissions',
62	        user
63	      );
64	      return NextResponse.json(
65	        { success: false, error: 'Insufficient permissions' },
66	        { status: 403 }
67	      );
68	    }
69	
70	    try {
71	      // ============================================================================
72	      // STEP 2: Parse query params
73	      // ============================================================================
74	      const { searchParams } = new URL(request.url);
75	      const licenceeId =
76	        searchParams.get('licenceeId') || searchParams.get('licencee');
77	
78	      const locationQuery: Record<string, unknown> = {
79	        membershipEnabled: true,
80	        deletedAt: { $lt: new Date('2025-01-01') },
81	      };
82	      if (licenceeId && licenceeId !== 'all')
83	        locationQuery.$or = [
84	          { 'rel.licencee': licenceeId },
85	          { 'rel.licencee': licenceeId },
86	        ];
87	
88	      // ============================================================================
89	      // STEP 3: Fetch locations
90	      // ============================================================================
91	      const locations = await GamingLocations.find(locationQuery, {
92	        _id: 1,
93	        name: 1,
94	        gameDayOffset: 1,
95	      }).lean<LocationDocument[]>();
96	      const locationIds = locations.map(loc => String(loc._id));
97	      const locationNameMap = locations.reduce(
98	        (acc, loc) => {
99	          acc[String(loc._id)] = loc.name;
100	          return acc;
101	        },
102	        {} as Record<string, string>
103	      );
104	
105	      if (locationIds.length === 0) {
106	        return NextResponse.json({
107	          success: true,
108	          data: {
109	            vaultBalance: { balance: 0, denominations: [] },
110	            metrics: {
111	              totalCashIn: 0,
112	              totalCashOut: 0,
113	              netCashFlow: 0,
114	              discrepancies: 0,
115	              pendingReviews: 0,
116	            },
117	            transactions: [],
118	            pendingShifts: [],
119	            floatRequests: [],
120	            cashDesks: [],
121	          },
122	        });
123	      }
124	
125	      // ============================================================================
126	      // STEP 4: Fetch shifts and float requests
127	      // ============================================================================
128	      const [
129	        VaultShiftModel,
130	        CashierShiftModel,
131	        FloatRequestModel,
132	        VaultTransactionModel,
133	      ] = await Promise.all([
134	        import('@/app/api/lib/models/vaultShift').then(m => m.default),
135	        import('@/app/api/lib/models/cashierShift').then(m => m.default),
136	        import('@/app/api/lib/models/floatRequest').then(m => m.default),
137	        import('@/app/api/lib/models/vaultTransaction').then(m => m.default),
138	      ]);
139	
140	      const [
141	        activeVaultShifts,
142	        pendingCashierShifts,
143	        activeCashierShifts,
144	        pendingFloatRequests,
145	        recentTransactions,
146	      ] = (await Promise.all([
147	        VaultShiftModel.find({
148	          locationId: { $in: locationIds },
149	          status: 'active',
150	        }).lean<VaultShiftDocument[]>(),
151	        CashierShiftModel.find({
152	          locationId: { $in: locationIds },
153	          status: 'pending_review',
154	        }).lean<CashierShiftDocument[]>(),
155	        CashierShiftModel.find({
156	          locationId: { $in: locationIds },
157	          status: { $in: ['active', 'pending_start'] },
158	        }).lean<CashierShiftDocument[]>(),
159	        FloatRequestModel.find({
160	          locationId: { $in: locationIds },
161	          status: 'pending',
162	        }).lean<Record<string, unknown>[]>(),
163	        VaultTransactionModel.find({ locationId: { $in: locationIds } })
164	          .sort({ timestamp: -1 })
165	          .limit(20)
166	          .lean<VaultTransactionDocument[]>(),
167	      ])) as unknown as [
168	        VaultShiftOverview[],
169	        CashierShiftOverview[],
170	        CashierShiftOverview[],
171	        Record<string, unknown>[],
172	        VaultTransactionOverview[],
173	      ];
174	
175	      // ============================================================================
176	      // STEP 5: Process active vault shifts
177	      // ============================================================================
178	      let totalBalance = 0;
179	      const aggregatedDenominations: Record<number, number> = {};
180	      activeVaultShifts.forEach(s => {
181	        totalBalance += s.closingBalance ?? s.openingBalance ?? 0;
182	        const denoms =
183	          (s.currentDenominations?.length
184	            ? s.currentDenominations
185	            : s.openingDenominations) || [];
186	        denoms.forEach(d => {
187	          aggregatedDenominations[d.denomination] =
188	            (aggregatedDenominations[d.denomination] || 0) + d.quantity;
189	        });
190	      });
191	
192	      const timePeriod = searchParams.get('timePeriod') || 'Today';
193	      const startDateParam = searchParams.get('startDate');
194	      const endDateParam = searchParams.get('endDate');
195	
196	      const { rangeStart, rangeEnd } = getGamingDayRangeForPeriod(
197	        timePeriod,
198	        8,
199	        startDateParam ? new Date(startDateParam) : undefined,
200	        endDateParam ? new Date(endDateParam) : undefined
201	      );
202	
203	      // ============================================================================
204	      // STEP 6: Process transactions
205	      // ============================================================================
206	      let totalIn = 0,
207	        totalOut = 0,
208	        totalDiscrepancies = 0,
209	        payouts = 0,
210	        payoutsCount = 0;
211	
212	      const filteredTransactions = (await VaultTransactionModel.find({
213	        locationId: { $in: locationIds },
214	        timestamp: { $gte: rangeStart, $lte: rangeEnd },
215	      }).lean<
216	        VaultTransactionDocument[]
217	      >()) as unknown as VaultTransactionOverview[];
218	      filteredTransactions.forEach(tx => {
219	        if (tx.to?.type === 'vault') totalIn += tx.amount;
220	        if (tx.from?.type === 'vault') totalOut += tx.amount;
221	        if (tx.type === 'payout') {
222	          payouts += tx.amount;
223	          payoutsCount += 1;
224	        }
225	      });
226	
227	      const totalCashierFloats =
228	        activeCashierShifts.reduce(
229	          (sum, s) => sum + (s.currentBalance || 0),
230	          0
231	        ) +
232	        pendingCashierShifts.reduce(
233	          (sum, s) => sum + (s.currentBalance || 0),
234	          0
235	        );
236	
237	      // ============================================================================
238	      // STEP 7: Process machine meters and discrepancies
239	      // ============================================================================
240	      const machineMeters = await Meters.aggregate([
241	        {
242	          $match: {
243	            location: { $in: locationIds },
244	            readAt: { $gte: rangeStart, $lte: rangeEnd },
245	          },
246	        },
247	        {
248	          $group: {
249	            _id: null,
250	            totalMoneyIn: { $sum: { $ifNull: ['$movement.drop', 0] } },
251	          },
252	        },
253	      ]);
254	      const totalMachineMoneyIn =
255	        machineMeters.length > 0 ? machineMeters[0].totalMoneyIn : 0;
256	
257	      pendingCashierShifts.forEach(s => {
258	        totalDiscrepancies += Math.abs(s.discrepancy || 0);
259	      });
260	
261	      // ============================================================================
262	      // STEP 8: Fetch user details
263	      // ============================================================================
264	      const userIds = new Set<string>();
265	      recentTransactions.forEach(tx => {
266	        if (tx.performedBy) userIds.add(tx.performedBy);
267	        if (tx.from?.type === 'cashier' && tx.from.id) userIds.add(tx.from.id);
268	        if (tx.to?.type === 'cashier' && tx.to.id) userIds.add(tx.to.id);
269	      });
270	
271	      let userMap: Record<string, UserOverview> = {};
272	      if (userIds.size > 0) {
273	        const UserModel = (await import('@/app/api/lib/models/user')).default;
274	        const users = await UserModel.find(
275	          { _id: { $in: Array.from(userIds) } },
276	          { 'profile.firstName': 1, 'profile.lastName': 1, username: 1 }
277	        ).lean<UserOverview[]>();
278	        userMap = users.reduce(
279	          (acc, u) => {
280	            acc[String(u._id)] = u;
281	            return acc;
282	          },
283	          {} as Record<string, UserOverview>
284	        );
285	      }
286	
287	      // ============================================================================
288	      // STEP 9: Format and return data
289	      // ============================================================================
290	      const formatTx = (
291	        tx: VaultTransactionOverview
292	      ): EnrichedVaultTransactionOverview => {
293	        const res = {
294	          ...tx,
295	          locationName: locationNameMap[tx.locationId],
296	        } as EnrichedVaultTransactionOverview;
297	        const perfUser = userMap[tx.performedBy || ''];
298	        if (perfUser?.profile?.firstName)
299	          res.performedByName = `${perfUser.profile.firstName} ${perfUser.profile.lastName}`;
300	        if (tx.from?.type === 'cashier' && tx.from.id) {
301	          const cash = userMap[tx.from.id];
302	          if (cash?.profile?.firstName)
303	            res.fromName = `Cashier (${cash.profile.firstName} ${cash.profile.lastName})`;
304	        }
305	        if (tx.to?.type === 'cashier' && tx.to.id) {
306	          const cash = userMap[tx.to.id];
307	          if (cash?.profile?.firstName)
308	            res.toName = `Cashier (${cash.profile.firstName} ${cash.profile.lastName})`;
309	        }
310	        return res;
311	      };
312	
313	      return NextResponse.json({
314	        success: true,
315	        data: {
316	          vaultBalance: {
317	            balance: totalBalance,
318	            denominations: Object.entries(aggregatedDenominations).map(
319	              ([d, q]) => ({ denomination: Number(d), quantity: q })
320	            ),
321	            totalCashOnPremises:
322	              totalBalance + totalCashierFloats + totalMachineMoneyIn,
323	            machineMoneyIn: totalMachineMoneyIn,
324	            cashierFloats: totalCashierFloats,
325	          },
326	          metrics: {
327	            totalCashIn: totalIn,
328	            totalCashOut: totalOut,
329	            netCashFlow: totalIn - totalOut,
330	            payouts,
331	            payoutsCount,
332	            discrepancies: totalDiscrepancies,
333	            pendingReviews: pendingCashierShifts.length,
334	          },
335	          transactions: recentTransactions.map(formatTx),
336	          pendingShifts: pendingCashierShifts.map(s => ({
337	            ...s,
338	            locationName: locationNameMap[s.locationId],
339	          })),
340	          floatRequests: pendingFloatRequests.map(r => ({
341	            ...r,
342	            locationName: locationNameMap[r.locationId as string],
343	          })),
344	          cashDesks: activeCashierShifts.map(s => ({
345	            _id: s._id,
346	            locationId: s.locationId,
347	            locationName: locationNameMap[s.locationId],
348	            name:
349	              s.cashierName ||
350	              s.cashierUsername ||
351	              `Cashier ${s.cashierId.substring(0, 4)}`,
352	            balance: s.currentBalance ?? s.openingBalance ?? 0,
353	            denominations:
354	              s.lastSyncedDenominations ?? s.openingDenominations ?? [],
355	            lastAudit: new Date(s.openedAt || s.createdAt).toISOString(),
356	            status: s.status === 'pending_start' ? 'inactive' : 'active',
357	          })),
358	          rangeStart: rangeStart.toISOString(),
359	          rangeEnd: rangeEnd.toISOString(),
360	        },
361	      });
362	
363	      const duration = Date.now() - startTime;
364	      logRouteFetch(
365	        functionName,
366	        'GET',
367	        '/api/vault/overview/global',
368	        1,
369	        user,
370	        duration
371	      );
372	    } catch (error: unknown) {
373	      const errorMessage =
374	        error instanceof Error
375	          ? error.message
376	          : 'Failed to fetch global vault overview';
377	      logRouteError(
378	        functionName,
379	        'GET',
380	        '/api/vault/overview/global',
381	        errorMessage,
382	        user
383	      );
384	      console.error('[Global Vault API] Error:', error);
385	      const message = error instanceof Error ? error.message : 'Unknown error';
386	      return NextResponse.json(
387	        { success: false, error: message },
388	        { status: 500 }
389	      );
390	    }
391	  });
392	}
