1	/**
2	 * Vault Metrics API
3	 */
4	
5	import { getUserLocationFilter } from '@/app/api/lib/helpers/licenceeFilter';
6	import CashierShiftModel from '@/app/api/lib/models/cashierShift';
7	import { GamingLocations } from '@/app/api/lib/models/gaminglocations';
8	import { Meters } from '@/app/api/lib/models/meters';
9	import VaultTransactionModel from '@/app/api/lib/models/vaultTransaction';
10	import { getGamingDayRangeForPeriod } from '@/lib/utils/gamingDayRange';
11	import type { TimePeriod } from '@/app/api/lib/types';
12	import { withApiAuth } from '@/app/api/lib/helpers/apiWrapper';
13	import {
14	  getMoneyInScale,
15	  getMoneyOutAndJackpotScale,
16	} from '@/app/api/lib/utils/reviewerScale';
17	import { NextRequest, NextResponse } from 'next/server';
18	import type { LocationDocument } from '@/lib/types/common';
19	import type {
20	  CashierShiftDocument,
21	  VaultTransactionDocument,
22	} from '@shared/types';
23	
24	/**
25	 * Main GET handler for vault metrics
26	 *
27	 * @param {string} locationId - ID of the location (REQUIRED)
28	 * @param {string} timePeriod - Named period ('Today', 'Yesterday', 'Last 7 Days', etc.)
29	 * @param {string} startDate - Manual ISO date start
30	 * @param {string} endDate - Manual ISO date end
31	 */
32	export async function GET(request: NextRequest) {
33	  return withApiAuth(request, async ({ user: userPayload, userRoles }) => {
34	    try {
35	      // ============================================================================
36	      // STEP 1: Parse and validate location
37	      // ============================================================================
38	      const { searchParams } = new URL(request.url);
39	      const locationId = searchParams.get('locationId');
40	      if (!locationId)
41	        return NextResponse.json(
42	          { success: false, error: 'Location ID is required' },
43	          { status: 400 }
44	        );
45	
46	      // ============================================================================
47	      // STEP 2: Enforce permissions
48	      // ============================================================================
49	      const allowedLocationIds = await getUserLocationFilter(
50	        (userPayload?.assignedLicencees as string[]) || [],
51	        undefined,
52	        (userPayload?.assignedLocations as string[]) || [],
53	        userRoles
54	      );
55	
56	      if (
57	        allowedLocationIds !== 'all' &&
58	        !allowedLocationIds.includes(locationId)
59	      ) {
60	        return NextResponse.json(
61	          { success: false, error: 'Access denied' },
62	          { status: 403 }
63	        );
64	      }
65	
66	      // ============================================================================
67	      // STEP 3: Process time range
68	      // ============================================================================
69	      const locationInfo = await GamingLocations.findOne(
70	        { _id: locationId },
71	        { gameDayOffset: 1 }
72	      ).lean<LocationDocument>();
73	      const gameDayOffset = locationInfo?.gameDayOffset ?? 8;
74	      const timePeriod = searchParams.get('timePeriod') || 'Today';
75	      const startDateParam = searchParams.get('startDate');
76	      const endDateParam = searchParams.get('endDate');
77	
78	      const { rangeStart, rangeEnd } = getGamingDayRangeForPeriod(
79	        timePeriod as TimePeriod,
80	        gameDayOffset,
81	        startDateParam ? new Date(startDateParam) : undefined,
82	        endDateParam ? new Date(endDateParam) : undefined
83	      );
84	
85	      // ============================================================================
86	      // STEP 4: Fetch metrics data
87	      // ============================================================================
88	      const [transactions, activeCashiersData, machineMeters] =
89	        await Promise.all([
90	          VaultTransactionModel.find({
91	            locationId,
92	            timestamp: { $gte: rangeStart, $lte: rangeEnd },
93	          }).lean<VaultTransactionDocument[]>(),
94	          CashierShiftModel.find(
95	            { locationId, status: { $in: ['active', 'pending_review'] } },
96	            { currentBalance: 1 }
97	          ).lean<CashierShiftDocument[]>(),
98	          Meters.aggregate([
99	            {
100	              $match: {
101	                location: locationId,
102	                readAt: { $gte: rangeStart, $lte: rangeEnd },
103	              },
104	            },
105	            {
106	              $group: {
107	                _id: null,
108	                totalMoneyIn: { $sum: { $ifNull: ['$movement.drop', 0] } },
109	              },
110	            },
111	          ]),
112	        ]);
113	
114	      // ============================================================================
115	      // STEP 5: Calculate base metrics
116	      // ============================================================================
117	      let totalCashIn = 0,
118	        totalCashOut = 0,
119	        payouts = 0,
120	        expenses = 0,
121	        payoutsCount = 0;
122	      transactions.forEach(tx => {
123	        if (['vault_reconciliation', 'vault_open'].includes(tx.type)) return;
124	        if (tx.to && tx.to.type === 'vault') totalCashIn += tx.amount;
125	        if (tx.from && tx.from.type === 'vault') totalCashOut += tx.amount;
126	        if (tx.type === 'expense') expenses += tx.amount;
127	        if (tx.type === 'payout') {
128	          payouts += tx.amount;
129	          payoutsCount += 1;
130	        }
131	      });
132	
133	      const totalCashierFloats = activeCashiersData.reduce(
134	        (sum, s) => sum + (s.currentBalance || 0),
135	        0
136	      );
137	      const totalMachineBalance =
138	        machineMeters.length > 0 ? machineMeters[0].totalMoneyIn : 0;
139	
140	      const metrics = {
141	        totalCashIn,
142	        totalCashOut,
143	        netCashFlow: totalCashIn - totalCashOut,
144	        payouts,
145	        payoutsCount,
146	        totalMachineBalance,
147	        totalCashierFloats,
148	        expenses,
149	      };
150	
151	      // ============================================================================
152	      // STEP 6: Apply reviewer scaling
153	      // ============================================================================
154	      const moneyInScale = getMoneyInScale(
155	        userPayload as {
156	          moneyInMultiplier?: number | null;
157	          roles?: string[];
158	          reviewerMultiplierStartTime?: Date | string | null;
159	        },
160	        rangeEnd
161	      );
162	      const moneyOutScale = getMoneyOutAndJackpotScale(
163	        userPayload as {
164	          moneyOutAndJackpotMultiplier?: number | null;
165	          roles?: string[];
166	          reviewerMultiplierStartTime?: Date | string | null;
167	        },
168	        rangeEnd
169	      );
170	      if (moneyInScale !== 1 || moneyOutScale !== 1) {
171	        metrics.totalCashIn *= moneyInScale;
172	        metrics.totalCashOut *= moneyOutScale;
173	        metrics.netCashFlow = metrics.totalCashIn - metrics.totalCashOut;
174	        metrics.payouts *= moneyOutScale;
175	        metrics.totalMachineBalance *= moneyOutScale;
176	        metrics.totalCashierFloats *= moneyOutScale;
177	        metrics.expenses *= moneyOutScale;
178	      }
179	
180	      // ============================================================================
181	      // STEP 7: Return metrics
182	      // ============================================================================
183	      return NextResponse.json({
184	        success: true,
185	        metrics,
186	        rangeStart: rangeStart.toISOString(),
187	        rangeEnd: rangeEnd.toISOString(),
188	      });
189	    } catch (error: unknown) {
190	      console.error('[Vault Metrics API] Error:', error);
191	      const message = error instanceof Error ? error.message : 'Unknown error';
192	      return NextResponse.json(
193	        { success: false, error: message },
194	        { status: 500 }
195	      );
196	    }
197	  });
198	}
