1	/**
2	 * Vault Metrics Breakdown API
3	 */
4	
5	import { getUserLocationFilter } from '@/app/api/lib/helpers/licenceeFilter';
6	import {
7	  logRouteFetch,
8	  logRouteError,
9	  extractUserFromRequest,
10	} from '@/app/api/lib/utils/routeLogger';
11	import { GamingLocations } from '@/app/api/lib/models/gaminglocations';
12	import VaultTransactionModel from '@/app/api/lib/models/vaultTransaction';
13	import { getGamingDayRangeForPeriod } from '@/lib/utils/gamingDayRange';
14	import type { TimePeriod } from '@/app/api/lib/types';
15	import { withApiAuth } from '@/app/api/lib/helpers/apiWrapper';
16	import { NextRequest, NextResponse } from 'next/server';
17	import type { LocationDocument } from '@/lib/types/common';
18	import type { VaultTransactionDocument } from '@shared/types';
19	
20	/**
21	 * Main GET handler for vault metrics breakdown
22	 *
23	 * @param {string} locationId - REQUIRED. Filter metrics by location.
24	 * @param {string} type - REQUIRED. Type of breakdown to retrieve.
25	 */
26	export async function GET(request: NextRequest) {
27	  const startTime = Date.now();
28	  const functionName = 'GET /api/vault/metrics/breakdown';
29	  const user = extractUserFromRequest(request);
30	
31	  return withApiAuth(request, async ({ user: userPayload, userRoles }) => {
32	    try {
33	      // ============================================================================
34	      // STEP 1: Parse query params
35	      // ============================================================================
36	      const { searchParams } = new URL(request.url);
37	      const locationId = searchParams.get('locationId');
38	      const type = searchParams.get('type');
39	      if (!locationId || !type) {
40	        logRouteError(
41	          functionName,
42	          'GET',
43	          '/api/vault/metrics/breakdown',
44	          'locationId and type are required',
45	          user
46	        );
47	        return NextResponse.json(
48	          { success: false, error: 'locationId and type are required' },
49	          { status: 400 }
50	        );
51	      }
52	
53	      // ============================================================================
54	      // STEP 2: Enforce permissions
55	      // ============================================================================
56	      const allowedLocationIds = await getUserLocationFilter(
57	        (userPayload?.assignedLicencees as string[]) || [],
58	        undefined,
59	        (userPayload?.assignedLocations as string[]) || [],
60	        userRoles
61	      );
62	
63	      if (
64	        allowedLocationIds !== 'all' &&
65	        !allowedLocationIds.includes(locationId)
66	      ) {
67	        logRouteError(
68	          functionName,
69	          'GET',
70	          '/api/vault/metrics/breakdown',
71	          'Access denied',
72	          user
73	        );
74	        return NextResponse.json(
75	          { success: false, error: 'Access denied' },
76	          { status: 403 }
77	        );
78	      }
79	
80	      // ============================================================================
81	      // STEP 3: Process time range
82	      // ============================================================================
83	      const locationInfo = await GamingLocations.findOne(
84	        { _id: locationId },
85	        { gameDayOffset: 1 }
86	      ).lean<LocationDocument>();
87	      const gameDayOffset = locationInfo?.gameDayOffset ?? 8;
88	      const timePeriod = searchParams.get('timePeriod') || 'Today';
89	      const startDateParam = searchParams.get('startDate');
90	      const endDateParam = searchParams.get('endDate');
91	
92	      const { rangeStart, rangeEnd } = getGamingDayRangeForPeriod(
93	        timePeriod as TimePeriod,
94	        gameDayOffset,
95	        startDateParam ? new Date(startDateParam) : undefined,
96	        endDateParam ? new Date(endDateParam) : undefined
97	      );
98	
99	      // ============================================================================
100	      // STEP 4: Build query and fetch transactions
101	      // ============================================================================
102	      const query: Record<string, unknown> = {
103	        locationId,
104	        timestamp: { $gte: rangeStart, $lte: rangeEnd },
105	        isVoid: { $ne: true },
106	      };
107	      if (type === 'in' || type === 'out')
108	        query.type = { $nin: ['vault_reconciliation', 'vault_open'] };
109	      if (type === 'in') query['to.type'] = 'vault';
110	      else if (type === 'out') query['from.type'] = 'vault';
111	      else if (type === 'payout') query.type = 'payout';
112	
113	      const transactions = await VaultTransactionModel.find(query)
114	        .sort({ timestamp: -1 })
115	        .lean<VaultTransactionDocument[]>();
116	
117	      // ============================================================================
118	      // STEP 5: Log and return results
119	      // ============================================================================
120	      const duration = Date.now() - startTime;
121	      logRouteFetch(
122	        functionName,
123	        'GET',
124	        '/api/vault/metrics/breakdown',
125	        transactions.length,
126	        user,
127	        duration
128	      );
129	
130	      return NextResponse.json({ success: true, data: transactions });
131	    } catch (error: unknown) {
132	      const errorMessage =
133	        error instanceof Error
134	          ? error.message
135	          : 'Failed to fetch metrics breakdown';
136	      logRouteError(
137	        functionName,
138	        'GET',
139	        '/api/vault/metrics/breakdown',
140	        errorMessage,
141	        user
142	      );
143	      console.error('[Vault Metrics Breakdown API] Error:', error);
144	      const message = error instanceof Error ? error.message : 'Unknown error';
145	      return NextResponse.json(
146	        { success: false, error: message },
147	        { status: 500 }
148	      );
149	    }
150	  });
151	}
