1	/**
2	 * Get Vault Balance API
3	 */
4	
5	import { withApiAuth } from '@/app/api/lib/helpers/apiWrapper';
6	import {
7	  logRouteFetch,
8	  logRouteError,
9	  extractUserFromRequest,
10	} from '@/app/api/lib/utils/routeLogger';
11	import CashierShiftModel from '@/app/api/lib/models/cashierShift';
12	import { Meters } from '@/app/api/lib/models/meters';
13	import UserModel from '@/app/api/lib/models/user';
14	import { VaultCollectionSession } from '@/app/api/lib/models/vault-collection-session';
15	import VaultShiftModel from '@/app/api/lib/models/vaultShift';
16	import { getGamingDayRangeForPeriod } from '@/lib/utils/gamingDayRange';
17	import type {
18	  CashierShiftDocument,
19	  GamingLocationDocument,
20	  VaultShiftDocument,
21	} from '@shared/types';
22	import type { LeanUserDocument } from 'shared/types/auth';
23	import type { VaultReconciliation } from '@/shared/types/vault';
24	import { NextRequest, NextResponse } from 'next/server';
25	import { isShiftStaleBackend } from '../../lib/helpers/vault/gamingDay';
26	import { GamingLocations } from '../../lib/models/gaminglocations';
27	
28	/**
29	 * Main GET handler for fetching vault balance
30	 *
31	 * @param {string} locationId - ID of the location to fetch balance for (REQUIRED)
32	 */
33	export async function GET(request: NextRequest) {
34	  const startTime = Date.now();
35	  const functionName = 'GET /api/vault/balance';
36	  const user = extractUserFromRequest(request);
37	
38	  return withApiAuth(request, async ({ userRoles }) => {
39	    try {
40	      // ============================================================================
41	      // STEP 1: Authenticate and authorize
42	      // ============================================================================
43	      const hasVaultAccess = userRoles
44	        .map(r => String(r).toLowerCase())
45	        .some(role =>
46	          ['developer', 'admin', 'manager', 'vault-manager'].includes(role)
47	        );
48	      if (!hasVaultAccess)
49	        return NextResponse.json(
50	          { success: false, error: 'Insufficient permissions' },
51	          { status: 403 }
52	        );
53	
54	      // ============================================================================
55	      // STEP 2: Find active or last closed shift
56	      // ============================================================================
57	      const { searchParams } = new URL(request.url);
58	      const locationId = searchParams.get('locationId');
59	      if (!locationId)
60	        return NextResponse.json(
61	          { success: false, error: 'locationId is required' },
62	          { status: 400 }
63	        );
64	
65	      const activeShift = await VaultShiftModel.findOne({
66	        locationId,
67	        status: 'active',
68	      }).lean<VaultShiftDocument>();
69	
70	      if (!activeShift) {
71	        const lastClosed = await VaultShiftModel.findOne({
72	          locationId,
73	          status: 'closed',
74	        })
75	          .sort({ closedAt: -1 })
76	          .lean<VaultShiftDocument>();
77	        const lastReconTime = lastClosed?.reconciliations?.length
78	          ? new Date(
79	              Math.max(
80	                ...lastClosed.reconciliations.map(r => {
81	                  const ts = (r as VaultReconciliation).timestamp;
82	                  return ts ? new Date(ts).getTime() : 0;
83	                })
84	              )
85	            )
86	          : null;
87	        const lastAuditTime = lastClosed?.closedAt
88	          ? lastReconTime && lastReconTime > lastClosed.closedAt
89	            ? lastReconTime
90	            : lastClosed.closedAt
91	          : lastReconTime || null;
92	
93	        return NextResponse.json({
94	          success: true,
95	          data: {
96	            balance: lastClosed?.closingBalance ?? 0,
97	            denominations: lastClosed?.closingDenominations ?? [],
98	            activeShiftId: undefined,
99	            lastReconciliation: lastReconTime || undefined,
100	            lastAudit: lastAuditTime ? lastAuditTime.toISOString() : 'Never',
101	            canClose: false,
102	            isInitial: !lastClosed,
103	            managerOnDuty: 'None',
104	          },
105	        });
106	      }
107	
108	      // ============================================================================
109	      // STEP 3: Calculate reconciliation and audit times
110	      // ============================================================================
111	      const lastReconTime =
112	        activeShift.reconciliations && activeShift.reconciliations.length > 0
113	          ? new Date(
114	              Math.max(
115	                ...activeShift.reconciliations.map(r =>
116	                  new Date(r.timestamp ?? 0).getTime()
117	                )
118	              )
119	            )
120	          : null;
121	      const lastAuditTime = activeShift.openedAt
122	        ? lastReconTime && lastReconTime > activeShift.openedAt
123	          ? lastReconTime
124	          : activeShift.openedAt
125	        : lastReconTime || null;
126	
127	      const vaultManager = await UserModel.findOne(
128	        { _id: activeShift.vaultManagerId },
129	        { profile: 1, username: 1 }
130	      ).lean<LeanUserDocument>();
131	      const managerName = vaultManager?.profile?.firstName
132	        ? `${vaultManager.profile.firstName} ${vaultManager.profile.lastName}`
133	        : vaultManager?.username || 'Unknown';
134	
135	      // ============================================================================
136	      // STEP 4: Aggregate cashier floats and machine meters
137	      // ============================================================================
138	      const activeCashierShifts = await CashierShiftModel.countDocuments({
139	        vaultShiftId: activeShift._id,
140	        status: { $in: ['active', 'pending_review', 'pending_start'] },
141	      });
142	      const activeCashiersData = await CashierShiftModel.find(
143	        { locationId, status: { $in: ['active', 'pending_review'] } },
144	        { currentBalance: 1 }
145	      ).lean<CashierShiftDocument[]>();
146	      const totalCashierFloats = activeCashiersData.reduce(
147	        (sum, s) => sum + (s.currentBalance || 0),
148	        0
149	      );
150	
151	      const locationInfo = await GamingLocations.findOne(
152	        { _id: locationId },
153	        { gameDayOffset: 1 }
154	      ).lean<GamingLocationDocument>();
155	      const { rangeStart, rangeEnd } = getGamingDayRangeForPeriod(
156	        'Today',
157	        locationInfo?.gameDayOffset ?? 8
158	      );
159	
160	      const machineMeters = await Meters.aggregate([
161	        {
162	          $match: {
163	            location: locationId,
164	            readAt: { $gte: rangeStart, $lte: rangeEnd },
165	          },
166	        },
167	        {
168	          $group: {
169	            _id: null,
170	            totalMoneyIn: { $sum: { $ifNull: ['$movement.drop', 0] } },
171	          },
172	        },
173	      ]);
174	      const totalMachineMoneyIn =
175	        machineMeters.length > 0 ? machineMeters[0].totalMoneyIn : 0;
176	
177	      const isCollectionDone = await VaultCollectionSession.exists({
178	        vaultShiftId: activeShift._id,
179	        status: 'completed',
180	        isEndOfDay: true,
181	      });
182	
183	      // ============================================================================
184	      // STEP 5: Return vault balance summary
185	      // ============================================================================
186	      const vaultBalanceVal =
187	        activeShift.closingBalance ?? activeShift.openingBalance ?? 0;
188	
189	      const duration = Date.now() - startTime;
190	      logRouteFetch(
191	        functionName,
192	        'GET',
193	        '/api/vault/balance',
194	        1,
195	        user,
196	        duration
197	      );
198	      return NextResponse.json({
199	        success: true,
200	        data: {
201	          balance: vaultBalanceVal,
202	          denominations: activeShift.currentDenominations?.length
203	            ? activeShift.currentDenominations
204	            : activeShift.openingDenominations,
205	          activeShiftId: activeShift._id,
206	          lastReconciliation: lastReconTime || undefined,
207	          lastAudit: lastAuditTime ? lastAuditTime.toISOString() : 'Never',
208	          managerOnDuty: managerName,
209	          canClose: activeCashierShifts === 0,
210	          blockReason:
211	            activeCashierShifts > 0
212	              ? `Still active: ${activeCashierShifts} cashier shifts`
213	              : undefined,
214	          totalCashOnPremises:
215	            vaultBalanceVal + totalCashierFloats + totalMachineMoneyIn,
216	          machineMoneyIn: totalMachineMoneyIn,
217	          cashierFloats: totalCashierFloats,
218	          openingBalance: activeShift.openingBalance,
219	          isReconciled: !!activeShift.isReconciled,
220	          isCollectionDone: !!isCollectionDone,
221	          openedAt: activeShift.openedAt,
222	          isStale: await isShiftStaleBackend(activeShift.openedAt!, locationId),
223	        },
224	      });
225	    } catch (error: unknown) {
226	      console.error('[Vault Balance] Error:', error);
227	      const message = error instanceof Error ? error.message : 'Unknown error';
228	      logRouteError(functionName, 'GET', '/api/vault/balance', message, user);
229	      return NextResponse.json(
230	        { success: false, error: message },
231	        { status: 500 }
232	      );
233	    }
234	  });
235	}
