1	/**
2	 * Add Cash to Vault API
3	 */
4	
5	import { withApiAuth } from '@/app/api/lib/helpers/apiWrapper';
6	import { logActivity } from '@/app/api/lib/helpers/activityLogger';
7	import {
8	  logRouteCreate,
9	  logRouteError,
10	  extractUserFromRequest,
11	} from '@/app/api/lib/utils/routeLogger';
12	import { getUserLocationFilter } from '@/app/api/lib/helpers/licenceeFilter';
13	import {
14	  updateVaultShiftInventory,
15	  validateDenominationTotal,
16	} from '@/app/api/lib/helpers/vault/inventory';
17	import VaultShiftModel from '@/app/api/lib/models/vaultShift';
18	import VaultTransactionModel from '@/app/api/lib/models/vaultTransaction';
19	import { generateMongoId } from '@/lib/utils/id';
20	import { NextRequest, NextResponse } from 'next/server';
21	
22	/**
23	 * POST /api/vault/add-cash
24	 *
25	 * @body {string} source - Source of funds ('Bank', 'Machine', etc.)
26	 * @body {number} amount - Total amount being added
27	 * @body {Array} denominations - Denomination breakdown
28	 * @body {string} notes - Optional transaction notes
29	 * @body {Object} bankDetails - Details if source is bank
30	 * @body {Array} machineIds - IDs if source is machine(s)
31	 */
32	export async function POST(request: NextRequest) {
33	  const startTime = Date.now();
34	  const functionName = 'POST /api/vault/add-cash';
35	  const user = extractUserFromRequest(request);
36	
37	  return withApiAuth(request, async ({ user: userPayload, userRoles }) => {
38	    try {
39	      // ============================================================================
40	      // STEP 1: Authenticate and authorize
41	      // ============================================================================
42	      const normalizedRoles = userRoles.map(r => String(r).toLowerCase());
43	      const hasVMAccess = normalizedRoles.some(role =>
44	        ['developer', 'admin', 'manager', 'vault-manager'].includes(role)
45	      );
46	      if (!hasVMAccess)
47	        return NextResponse.json(
48	          { success: false, error: 'Insufficient permissions' },
49	          { status: 403 }
50	        );
51	
52	      // ============================================================================
53	      // STEP 2: Parse and validate request body
54	      // ============================================================================
55	      const { source, amount, denominations, notes, bankDetails, machineIds } =
56	        await request.json();
57	      if (!source || !amount || !denominations)
58	        return NextResponse.json(
59	          { success: false, error: 'Missing required fields' },
60	          { status: 400 }
61	        );
62	
63	      // ============================================================================
64	      // STEP 3: Check active vault shift and location permissions
65	      // ============================================================================
66	      const activeVaultShift = await VaultShiftModel.findOne({
67	        vaultManagerId: userPayload._id,
68	        status: 'active',
69	      });
70	      if (!activeVaultShift)
71	        return NextResponse.json(
72	          { success: false, error: 'No active vault shift found' },
73	          { status: 400 }
74	        );
75	
76	      const allowedLocationIds = await getUserLocationFilter(
77	        userPayload.assignedLicencees || [],
78	        undefined,
79	        userPayload.assignedLocations || [],
80	        userRoles
81	      );
82	
83	      if (
84	        allowedLocationIds !== 'all' &&
85	        !allowedLocationIds.includes(String(activeVaultShift.locationId))
86	      ) {
87	        return NextResponse.json(
88	          {
89	            success: false,
90	            error: `Access denied for location ${activeVaultShift.locationId}`,
91	          },
92	          { status: 403 }
93	        );
94	      }
95	
96	      if (!validateDenominationTotal(amount, denominations))
97	        return NextResponse.json(
98	          { success: false, error: 'Denomination total mismatch' },
99	          { status: 400 }
100	        );
101	
102	      // ============================================================================
103	      // STEP 4: Generate transaction and update inventory
104	      // ============================================================================
105	      const transactionId = await generateMongoId();
106	      const now = new Date();
107	      const before =
108	        activeVaultShift.closingBalance ?? activeVaultShift.openingBalance;
109	
110	      const vaultTransaction = new VaultTransactionModel({
111	        _id: transactionId,
112	        locationId: activeVaultShift.locationId,
113	        timestamp: now,
114	        type: 'add_cash',
115	        from: {
116	          type: source === 'Machine' ? 'machine' : 'external',
117	          id:
118	            source === 'Machine' && machineIds?.length === 1
119	              ? machineIds[0]
120	              : source,
121	        },
122	        to: { type: 'vault' },
123	        fromName: source,
124	        toName: 'Vault',
125	        amount,
126	        denominations,
127	        vaultBalanceBefore: before,
128	        vaultBalanceAfter: before + amount,
129	        vaultShiftId: activeVaultShift._id,
130	        performedBy: userPayload._id,
131	        performedByName: userPayload.username || '',
132	        bankDetails,
133	        expenseDetails: machineIds?.length
134	          ? {
135	              machineIds,
136	              isMachineRepair: false,
137	              description: `Cash from machines: ${machineIds.join(', ')}`,
138	            }
139	          : undefined,
140	        notes: `Cash from ${source}${notes ? `: ${notes}` : ''}`,
141	      });
142	
143	      await vaultTransaction.save();
144	      await updateVaultShiftInventory(
145	        activeVaultShift,
146	        amount,
147	        denominations,
148	        true
149	      );
150	
151	      // ============================================================================
152	      // STEP 5: Log activity and return success
153	      // ============================================================================
154	      await logActivity({
155	        userId: userPayload._id,
156	        username: userPayload.username,
157	        action: 'create',
158	        details: `Added cash from ${source}: $${amount}`,
159	        metadata: {
160	          resource: 'vault',
161	          resourceId: activeVaultShift.locationId,
162	          transactionId,
163	          source,
164	        },
165	      });
166	
167	      const duration = Date.now() - startTime;
168	      logRouteCreate(
169	        functionName,
170	        'POST',
171	        '/api/vault/add-cash',
172	        1,
173	        user,
174	        duration
175	      );
176	      return NextResponse.json({
177	        success: true,
178	        transaction: vaultTransaction,
179	      });
180	    } catch (error: unknown) {
181	      console.error('[Add Cash API] Error:', error);
182	      const message = error instanceof Error ? error.message : 'Unknown error';
183	      logRouteError(functionName, 'POST', '/api/vault/add-cash', message, user);
184	      return NextResponse.json(
185	        { success: false, error: message },
186	        { status: 500 }
187	      );
188	    }
189	  });
190	}
