22	/**
23	 * Main POST handler for removing cash from vault
24	 *
25	 * @body {string} reason - REQUIRED. Reason for the cash removal.
26	 * @body {number} amount - REQUIRED. Total amount to remove.
27	 * @body {Object} denominations - REQUIRED. Denomination breakdown of the removal.
28	 * @body {string} notes - Optional. Additional context.
29	 */
30	export async function POST(request: NextRequest) {
31	  const startTime = Date.now();
32	  const functionName = 'POST /api/vault/remove-cash';
33	  const user = extractUserFromRequest(request);
34	
35	  return withApiAuth(request, async ({ user: userPayload, userRoles }) => {
36	    try {
37	      // ============================================================================
38	      // STEP 1: Validate permissions
39	      // ============================================================================
40	      const normalizedRoles = userRoles.map(r => String(r).toLowerCase());
41	      const hasVMAccess = normalizedRoles.some(role =>
42	        ['developer', 'admin', 'manager', 'vault-manager'].includes(role)
43	      );
44	      if (!hasVMAccess) {
45	        logRouteError(
46	          functionName,
47	          'POST',
48	          '/api/vault/remove-cash',
49	          'Insufficient permissions',
50	          user
51	        );
52	        return NextResponse.json(
53	          { success: false, error: 'Insufficient permissions' },
54	          { status: 403 }
55	        );
56	      }
57	
58	      // ============================================================================
59	      // STEP 2: Parse and validate body
60	      // ============================================================================
61	      const { reason, amount, denominations, notes } = await request.json();
62	      if (!reason || !amount || !denominations) {
63	        logRouteError(
64	          functionName,
65	          'POST',
66	          '/api/vault/remove-cash',
67	          'Missing required fields',
68	          user
69	        );
70	        return NextResponse.json(
71	          { success: false, error: 'Missing required fields' },
72	          { status: 400 }
73	        );
74	      }
75	
76	      // ============================================================================
77	      // STEP 3: Validate vault shift
78	      // ============================================================================
79	      const activeVaultShift = await VaultShiftModel.findOne({
80	        vaultManagerId: userPayload._id,
81	        status: 'active',
82	      });
83	      if (!activeVaultShift) {
84	        logRouteError(
85	          functionName,
86	          'POST',
87	          '/api/vault/remove-cash',
88	          'No active vault shift found',
89	          user
90	        );
91	        return NextResponse.json(
92	          { success: false, error: 'No active vault shift found' },
93	          { status: 400 }
94	        );
95	      }
96	
97	      // ============================================================================
98	      // STEP 4: Validate location access
99	      // ============================================================================
100	      const allowedLocationIds = await getUserLocationFilter(
101	        userPayload.assignedLicencees || [],
102	        undefined,
103	        userPayload.assignedLocations || [],
104	        userRoles
105	      );
106	
107	      if (
108	        allowedLocationIds !== 'all' &&
109	        !allowedLocationIds.includes(String(activeVaultShift.locationId))
110	      ) {
111	        logRouteError(
112	          functionName,
113	          'POST',
114	          '/api/vault/remove-cash',
115	          `Access denied for location ${activeVaultShift.locationId}`,
116	          user
117	        );
118	        return NextResponse.json(
119	          {
120	            success: false,
121	            error: `Access denied for location ${activeVaultShift.locationId}`,
122	          },
123	          { status: 403 }
124	        );
125	      }
126	
127	      // ============================================================================
128	      // STEP 5: Validate denomination totals
129	      // ============================================================================
130	      if (!validateDenominationTotal(amount, denominations)) {
131	        logRouteError(
132	          functionName,
133	          'POST',
134	          '/api/vault/remove-cash',
135	          'Denomination total mismatch',
136	          user
137	        );
138	        return NextResponse.json(
139	          { success: false, error: 'Denomination total mismatch' },
140	          { status: 400 }
141	        );
142	      }
143	
144	      // ============================================================================
145	      // STEP 6: Process removal and transaction
146	      // ============================================================================
147	      const transactionId = await generateMongoId();
148	      const now = new Date();
149	      const before =
150	        activeVaultShift.closingBalance ?? activeVaultShift.openingBalance;
151	
152	      const vaultTransaction = new VaultTransactionModel({
153	        _id: transactionId,
154	        locationId: activeVaultShift.locationId,
155	        timestamp: now,
156	        type: 'vault_close',
157	        from: { type: 'vault' },
158	        to: { type: 'external' },
159	        amount,
160	        denominations,
161	        vaultBalanceBefore: before,
162	        vaultBalanceAfter: before - amount,
163	        vaultShiftId: activeVaultShift._id,
164	        performedBy: userPayload._id,
165	        performedByName: userPayload.username || '',
166	        notes: notes
167	          ? `Reason: ${reason} - Notes: ${notes}`
168	          : `Reason: ${reason}`,
169	      });
170	
171	      await vaultTransaction.save();
172	
173	      // ============================================================================
174	      // STEP 7: Update inventory and return
175	      // ============================================================================
176	      await updateVaultShiftInventory(
177	        activeVaultShift,
178	        amount,
179	        denominations,
180	        false
181	      );
182	
183	      await logActivity({
184	        userId: userPayload._id,
185	        username: userPayload.username,
186	        action: 'create',
187	        details: `Removed cash from vault ($${amount}) for: ${reason}`,
188	        metadata: {
189	          resource: 'vault',
190	          resourceId: activeVaultShift.locationId,
191	          transactionId,
192	          reason,
193	        },
194	      });
195	
196	      const duration = Date.now() - startTime;
197	      logRouteCreate(
198	        functionName,
199	        'POST',
200	        '/api/vault/remove-cash',
201	        1,
202	        user,
203	        duration
204	      );
205	
206	      return NextResponse.json({
207	        success: true,
208	        transaction: vaultTransaction,
209	      });
210	    } catch (error: unknown) {
211	      const errorMessage =
212	        error instanceof Error
213	          ? error.message
214	          : 'Failed to remove cash from vault';
215	      logRouteError(
216	        functionName,
217	        'POST',
218	        '/api/vault/remove-cash',
219	        errorMessage,
220	        user
221	      );
222	      console.error('[Remove Cash API] Error:', error);
223	      const message = error instanceof Error ? error.message : 'Unknown error';
224	      return NextResponse.json(
225	        { success: false, error: message },
226	        { status: 500 }
227	      );
228	    }
229	  });
230	}
