1	/**
2	 * Vault Reconciliation API
3	 */
4	
5	import { withApiAuth } from '@/app/api/lib/helpers/apiWrapper';
6	import { logActivity } from '@/app/api/lib/helpers/activityLogger';
7	import {
8	  logRouteError,
9	  extractUserFromRequest,
10	  logRouteUpdate,
11	} from '@/app/api/lib/utils/routeLogger';
12	import { getUserLocationFilter } from '@/app/api/lib/helpers/licenceeFilter';
13	import VaultTransactionModel from '@/app/api/lib/models/vaultTransaction';
14	import { validateDenominations } from '@/lib/helpers/vault/calculations';
15	import { generateMongoId } from '@/lib/utils/id';
16	import { NextRequest, NextResponse } from 'next/server';
17	import VaultShiftModel from '../../lib/models/vaultShift';
18	
19	/**
20	 * Main POST handler for vault reconciliation
21	 *
22	 * @body {string} vaultShiftId - REQUIRED. The ID of the shift being reconciled.
23	 * @body {number} newBalance - REQUIRED. The counted balance to set.
24	 * @body {Object} denominations - REQUIRED. Denomination counts for the new balance.
25	 * @body {string} reason - REQUIRED. Reason for the adjustment.
26	 * @body {string} comment - Optional. Additional details.
27	 */
28	export async function POST(request: NextRequest) {
29	  const startTime = Date.now();
30	  const functionName = 'POST /api/vault/reconcile';
31	  const user = extractUserFromRequest(request);
32	
33	  return withApiAuth(request, async ({ user: payload, userRoles }) => {
34	    try {
35	      // ============================================================================
36	      // STEP 1: Check permissions
37	      // ============================================================================
38	      const hasVaultAccess = userRoles
39	        .map(r => String(r).toLowerCase())
40	        .some(role =>
41	          ['developer', 'admin', 'manager', 'vault-manager'].includes(role)
42	        );
43	      if (!hasVaultAccess) {
44	        logRouteError(
45	          functionName,
46	          'POST',
47	          '/api/vault/reconcile',
48	          'Insufficient permissions',
49	          user
50	        );
51	        return NextResponse.json(
52	          { success: false, error: 'Insufficient permissions' },
53	          { status: 403 }
54	        );
55	      }
56	
57	      // ============================================================================
58	      // STEP 2: Parse and validate body
59	      // ============================================================================
60	      const { vaultShiftId, newBalance, denominations, reason, comment } =
61	        await request.json();
62	      const finalDesc = (reason || comment || '').trim();
63	
64	      // ============================================================================
65	      // STEP 3: Validate denominations
66	      // ============================================================================
67	      const validation = validateDenominations(denominations);
68	      if (!validation.valid) {
69	        logRouteError(
70	          functionName,
71	          'POST',
72	          '/api/vault/reconcile',
73	          'Invalid denominations',
74	          user
75	        );
76	        return NextResponse.json(
77	          {
78	            success: false,
79	            error: 'Invalid denominations',
80	            details: validation.errors,
81	          },
82	          { status: 400 }
83	        );
84	      }
85	      if (validation.total !== newBalance) {
86	        logRouteError(
87	          functionName,
88	          'POST',
89	          '/api/vault/reconcile',
90	          `Balance mismatch: $${validation.total} vs $${newBalance}`,
91	          user
92	        );
93	        return NextResponse.json(
94	          {
95	            success: false,
96	            error: `Balance mismatch: $${validation.total} vs $${newBalance}`,
97	          },
98	          { status: 400 }
99	        );
100	      }
101	
102	      // ============================================================================
103	      // STEP 4: Validate vault shift
104	      // ============================================================================
105	      const vaultShift = await VaultShiftModel.findOne({ _id: vaultShiftId });
106	      if (!vaultShift) {
107	        logRouteError(
108	          functionName,
109	          'POST',
110	          '/api/vault/reconcile',
111	          'Vault shift not found',
112	          user
113	        );
114	        return NextResponse.json(
115	          { success: false, error: 'Vault shift not found' },
116	          { status: 404 }
117	        );
118	      }
119	      if (vaultShift.status === 'closed') {
120	        logRouteError(
121	          functionName,
122	          'POST',
123	          '/api/vault/reconcile',
124	          'Cannot reconcile closed shift',
125	          user
126	        );
127	        return NextResponse.json(
128	          { success: false, error: 'Cannot reconcile closed shift' },
129	          { status: 400 }
130	        );
131	      }
132	
133	      // ============================================================================
134	      // STEP 5: Validate location access
135	      // ============================================================================
136	      const allowedLocIds = await getUserLocationFilter(
137	        payload.assignedLicencees || [],
138	        undefined,
139	        payload.assignedLocations || [],
140	        userRoles
141	      );
142	      if (
143	        allowedLocIds !== 'all' &&
144	        !allowedLocIds.includes(String(vaultShift.locationId))
145	      ) {
146	        logRouteError(
147	          functionName,
148	          'POST',
149	          '/api/vault/reconcile',
150	          'Access denied for this location vault',
151	          user
152	        );
153	        return NextResponse.json(
154	          { success: false, error: 'Access denied for this location vault' },
155	          { status: 403 }
156	        );
157	      }
158	
159	      // ============================================================================
160	      // STEP 6: Update vault shift
161	      // ============================================================================
162	      const prevBalance =
163	        vaultShift.reconciliations.length > 0
164	          ? vaultShift.reconciliations[vaultShift.reconciliations.length - 1]
165	              .newBalance
166	          : vaultShift.openingBalance;
167	      const now = new Date();
168	      vaultShift.reconciliations.push({
169	        timestamp: now,
170	        previousBalance: prevBalance,
171	        newBalance,
172	        denominations,
173	        reason: finalDesc,
174	        comment: finalDesc,
175	      });
176	      vaultShift.currentDenominations = denominations;
177	      vaultShift.closingBalance = newBalance;
178	      vaultShift.isReconciled = true;
179	      vaultShift.updatedAt = now;
180	      await vaultShift.save();
181	
182	      // ============================================================================
183	      // STEP 7: Create transaction and log activity
184	      // ============================================================================
185	      const txId = await generateMongoId(),
186	        adj = newBalance - prevBalance;
187	      const transaction = await VaultTransactionModel.create({
188	        _id: txId,
189	        locationId: vaultShift.locationId,
190	        timestamp: now,
191	        type: 'vault_reconciliation',
192	        from: adj >= 0 ? { type: 'external' } : { type: 'vault' },
193	        to: adj >= 0 ? { type: 'vault' } : { type: 'external' },
194	        amount: Math.abs(adj),
195	        denominations,
196	        vaultBalanceBefore: prevBalance,
197	        vaultBalanceAfter: newBalance,
198	        vaultShiftId,
199	        performedBy: payload._id,
200	        performedByName: payload.username || '',
201	        notes: finalDesc,
202	        auditComment: finalDesc,
203	        isVoid: false,
204	        createdAt: now,
205	      });
206	
207	      await logActivity({
208	        userId: payload._id,
209	        username: payload.username,
210	        action: 'update',
211	        details: `Reconciled vault balance. New: $${newBalance} (Adj: $${adj})`,
212	        metadata: {
213	          resource: 'vault',
214	          resourceId: vaultShift.locationId,
215	          transactionId: txId,
216	          shiftId: vaultShift._id.toString(),
217	          reason: finalDesc,
218	        },
219	      });
220	
221	      const duration = Date.now() - startTime;
222	      logRouteUpdate(
223	        functionName,
224	        'POST',
225	        '/api/vault/reconcile',
226	        1,
227	        user,
228	        duration
229	      );
230	
231	      // ============================================================================
232	      // STEP 8: Return response
233	      // ============================================================================
234	      return NextResponse.json({
235	        success: true,
236	        vaultShift: vaultShift.toObject(),
237	        transaction: transaction.toObject(),
238	        adjustment: adj,
239	      });
240	    } catch (e) {
241	      const errorMessage =
242	        e instanceof Error ? e.message : 'Failed to reconcile vault';
243	      logRouteError(
244	        functionName,
245	        'POST',
246	        '/api/vault/reconcile',
247	        errorMessage,
248	        user
249	      );
250	      console.error(
251	        '[Vault Reconcile] Error:',
252	        e instanceof Error ? e.message : 'Unknown error'
253	      );
254	      return NextResponse.json(
255	        { success: false, error: 'Internal server error' },
256	        { status: 500 }
257	      );
258	    }
259	  });
260	}
