19	/**
20	 * POST /api/vault/initialize
21	 *
22	 * @body {string} locationId - ID of the location to initialize (REQUIRED)
23	 * @body {string} notes - Optional initialization notes
24	 * @body {number} openingBalance - Manual override for opening balance
25	 * @body {Array} denominations - Manual override for opening denominations
26	 */
27	export async function POST(request: NextRequest) {
28	  const startTime = Date.now();
29	  const functionName = 'POST /api/vault/initialize';
30	  const user = extractUserFromRequest(request);
31	
32	  return withApiAuth(request, async ({ user: userPayload, userRoles }) => {
33	    try {
34	      // ============================================================================
35	      // STEP 1: Validate permissions
36	      // ============================================================================
37	      const hasVaultAccess = userRoles
38	        .map(r => String(r).toLowerCase())
39	        .some(role =>
40	          ['developer', 'admin', 'manager', 'vault-manager'].includes(role)
41	        );
42	      if (!hasVaultAccess) {
43	        logRouteError(
44	          functionName,
45	          'POST',
46	          '/api/vault/initialize',
47	          'Insufficient permissions',
48	          user
49	        );
50	        return NextResponse.json(
51	          { success: false, error: 'Insufficient permissions' },
52	          { status: 403 }
53	        );
54	      }
55	
56	      // ============================================================================
57	      // STEP 2: Parse and validate input
58	      // ============================================================================
59	      const body = await request.json();
60	      const { locationId, notes } = body;
61	      let { openingBalance, denominations } = body;
62	      if (!locationId) {
63	        logRouteError(
64	          functionName,
65	          'POST',
66	          '/api/vault/initialize',
67	          'locationId required',
68	          user
69	        );
70	        return NextResponse.json(
71	          { success: false, error: 'locationId required' },
72	          { status: 400 }
73	        );
74	      }
75	
76	      // ============================================================================
77	      // STEP 3: Determine opening balance and denominations
78	      // ============================================================================
79	      if (openingBalance === undefined || !denominations?.length) {
80	        const lastClosed = await VaultShiftModel.findOne({
81	          locationId,
82	          status: 'closed',
83	        })
84	          .sort({ closedAt: -1 })
85	          .lean<VaultShiftDocument>();
86	        openingBalance = lastClosed?.closingBalance ?? 0;
87	        denominations = lastClosed?.closingDenominations ?? [];
88	      }
89	
90	      // ============================================================================
91	      // STEP 4: Validate denominations
92	      // ============================================================================
93	      if (denominations.length > 0) {
94	        const validation = validateDenominations(denominations);
95	        if (!validation.valid) {
96	          logRouteError(
97	            functionName,
98	            'POST',
99	            '/api/vault/initialize',
100	            'Invalid denominations',
101	            user
102	          );
103	          return NextResponse.json(
104	            {
105	              success: false,
106	              error: 'Invalid denominations',
107	              details: validation.errors,
108	            },
109	            { status: 400 }
110	          );
111	        }
112	        if (validation.total !== openingBalance) {
113	          logRouteError(
114	            functionName,
115	            'POST',
116	            '/api/vault/initialize',
117	            `Balance mismatch: $${validation.total} vs $${openingBalance}`,
118	            user
119	          );
120	          return NextResponse.json(
121	            {
122	              success: false,
123	              error: `Balance mismatch: $${validation.total} vs $${openingBalance}`,
124	            },
125	            { status: 400 }
126	          );
127	        }
128	      }
129	
130	      // ============================================================================
131	      // STEP 5: Check for active vault shift
132	      // ============================================================================
133	      if (await VaultShiftModel.findOne({ locationId, status: 'active' })) {
134	        logRouteError(
135	          functionName,
136	          'POST',
137	          '/api/vault/initialize',
138	          'Active vault shift already exists',
139	          user
140	        );
141	        return NextResponse.json(
142	          { success: false, error: 'Active vault shift already exists' },
143	          { status: 409 }
144	        );
145	      }
146	
147	      // ============================================================================
148	      // STEP 6: Initialize vault shift and transaction
149	      // ============================================================================
150	      const vaultShiftId = await generateMongoId();
151	      const now = new Date();
152	      const vaultShift = await VaultShiftModel.create({
153	        _id: vaultShiftId,
154	        locationId,
155	        vaultManagerId: userPayload._id,
156	        status: 'active',
157	        openedAt: now,
158	        openingBalance,
159	        openingDenominations: denominations,
160	        currentDenominations: denominations,
161	        reconciliations: [],
162	        canClose: true,
163	        createdAt: now,
164	        updatedAt: now,
165	      });
166	
167	      const transactionId = await generateMongoId();
168	      const transaction = await VaultTransactionModel.create({
169	        _id: transactionId,
170	        locationId,
171	        timestamp: now,
172	        type: 'vault_open',
173	        from: { type: 'external' },
174	        to: { type: 'vault' },
175	        amount: openingBalance,
176	        denominations,
177	        vaultBalanceBefore: 0,
178	        vaultBalanceAfter: openingBalance,
179	        vaultShiftId,
180	        performedBy: userPayload._id,
181	        notes: notes || 'Initial vault setup',
182	        isVoid: false,
183	        createdAt: now,
184	      });
185	
186	      // ============================================================================
187	      // STEP 7: Log activity and return
188	      // ============================================================================
189	      await logActivity({
190	        userId: userPayload._id,
191	        username: userPayload.username || userPayload.emailAddress,
192	        action: 'create',
193	        details: `Initialized vault for location ${locationId} ($${openingBalance})`,
194	        metadata: {
195	          resource: 'location',
196	          resourceId: locationId,
197	          vaultShiftId,
198	          transactionId,
199	        },
200	      });
201	
202	      const duration = Date.now() - startTime;
203	      logRouteCreate(
204	        functionName,
205	        'POST',
206	        '/api/vault/initialize',
207	        1,
208	        user,
209	        duration
210	      );
211	
212	      return NextResponse.json(
213	        {
214	          success: true,
215	          message: 'Vault initialized',
216	          vaultShift: vaultShift.toObject(),
217	          transaction: transaction.toObject(),
218	        },
219	        { status: 201 }
220	      );
221	    } catch (error: unknown) {
222	      const errorMessage =
223	        error instanceof Error ? error.message : 'Failed to initialize vault';
224	      logRouteError(
225	        functionName,
226	        'POST',
227	        '/api/vault/initialize',
228	        errorMessage,
229	        user
230	      );
231	      console.error('[Vault Initialize] Error:', error);
232	      const message = error instanceof Error ? error.message : 'Unknown error';
233	      return NextResponse.json(
234	        { success: false, error: message },
235	        { status: 500 }
236	      );
237	    }
238	  });
239	}
